+  /**
+   * Creates a conditional writer for the specified data level with configured thread pool size.
+   */
+  private ConditionalWriter createConditionalWriter(DataLevel dataLevel)
+      throws TableNotFoundException {
+    if (dataLevel == DataLevel.ROOT) {
+      return new RootConditionalWriter(context);
+    } else {
+      int maxThreads = context.getConfiguration()
+          .getCount(Property.MANAGER_AMPLE_CONDITIONAL_WRITER_THREADS_MAX);
+      ConditionalWriterConfig cwConfig = new ConditionalWriterConfig().setMaxWriteThreads(maxThreads);
+      return context.createConditionalWriter(getTableMapper().apply(dataLevel), cwConfig);
+    }
+  }
+
+  /**
+   * Returns the appropriate conditional writer supplier for the given data level.
+   */
+  Supplier<ConditionalWriter> getConditionalWriterSupplier(DataLevel dataLevel) {
+    switch (dataLevel) {
+      case METADATA:
+        return metadataConditionalWriter;
+      case USER:
+        return userConditionalWriter;
+      case ROOT:
+        // ROOT uses RootConditionalWriter which is created per-mutation, so we return a fresh
+        // supplier
+        return () -> {
+          try {
+            return createConditionalWriter(DataLevel.ROOT);
+          } catch (TableNotFoundException e) {
+            throw new IllegalStateException("Root table access failed", e);
+          }
+        };
+      default:
+        throw new IllegalArgumentException("Unsupported data level: " + dataLevel);
+    }
   }

