    50→/**
    51→ * Accumulo Metadata Persistence Layer. Entry point and abstractions layer for reading and updating
    52→ * persisted Accumulo metadata. This metadata may be stored in Zookeeper or in Accumulo system
    53→ * tables.
    54→ *
    55→ * <p>
    56→ * This interface seeks to satisfy the following goals.
    57→ *
    58→ * <ul>
    59→ * <li>Provide a single entry point for all reading and writing of Accumulo Metadata.
    60→ * <li>The root tablet persists its data in Zookeeper. Metadata tablets persist their data in root
    61→ * tablet. All other tablets persist their data in the metadata table. This interface abstracts how
    62→ * and where information for a tablet is actually persisted.
    63→ * <li>Before the creation of this interface, many concurrent metadata table updates resulted in
    64→ * separate synchronous RPCs. The design of this interface allows batching of metadata table updates
    65→ * within a tablet server for cluster wide efficiencies. Batching is not required by
    66→ * implementations, but the design of the interface makes it possible.
    67→ * <li>Make code that updates Accumulo persistent metadata more concise. Before this interface
    68→ * existed, there was a lot of redundant and verbose code for updating metadata.
    69→ * <li>Reduce specialized code for the root tablet. Currently there is specialized code to manage
    70→ * the root tablets files that is different from all other tablets. This interface is the beginning
    71→ * of an effort to remove this specialized code. See #936
    72→ * </ul>
    73→ */
    74→public interface Ample {
    75→
    76→  /**
    77→   * Accumulo is a distributed tree with three levels. This enum is used to communicate to Ample
    78→   * that code is interested in operating on the metadata of a data level. Sometimes tables ids or
    79→   * key extents are passed to Ample in lieu of a data level, in these cases the data level is
    80→   * derived from the table id.
    81→   */
    82→  public enum DataLevel {
    83→    ROOT(null, null),
    84→    METADATA(SystemTables.ROOT.tableName(), SystemTables.ROOT.tableId()),
    85→    USER(SystemTables.METADATA.tableName(), SystemTables.METADATA.tableId());
    86→
    87→    private final String table;
    88→    private final TableId id;
    89→
    90→    private DataLevel(String table, TableId id) {
    91→      this.table = table;
    92→      this.id = id;
    93→    }
    94→
    95→    /**
    96→     * @return The name of the Accumulo table in which this data level stores its metadata.
    97→     */
    98→    public String metaTable() {
    99→      if (table == null) {
   100→        throw new UnsupportedOperationException();
   101→      }
   102→      return table;
   103→    }
   104→
   105→    /**
   106→     * @return The Id of the Accumulo table in which this data level stores its metadata.
   107→     */
   108→    public TableId metaTableId() {
   109→      if (id == null) {
   110→        throw new UnsupportedOperationException();
   111→      }
   112→      return id;
   113→    }
   114→
   115→    public static DataLevel of(TableId tableId) {
   116→      if (tableId.equals(SystemTables.ROOT.tableId())) {
   117→        return DataLevel.ROOT;
   118→      } else if (tableId.equals(SystemTables.METADATA.tableId())) {
   119→        return DataLevel.METADATA;
   120→      } else {
   121→        return DataLevel.USER;
   122→      }
   123→    }
   124→  }
   125→
   126→  /**
   127→   * Enables status based processing of GcCandidates.
   128→   */
   129→  public enum GcCandidateType {
   130→    /**
   131→     * Candidates which have corresponding file references still present in tablet metadata.
   132→     */
   133→    INUSE,
   134→    /**
   135→     * Candidates that have no matching file references and can be removed from the system.
   136→     */
   137→    VALID,
   138→    /**
   139→     * Candidates that are malformed.
   140→     */
   141→    INVALID
   142→  }
   143→
   144→  /**
   145→   * Read a single tablets metadata. No checking is done for prev row, so it could differ.
   146→   *
   147→   * @param extent Reads tablet metadata using the table id and end row from this extent.
   148→   * @param colsToFetch What tablets columns to fetch. If empty, then everything is fetched.
   149→   */
   150→  TabletMetadata readTablet(KeyExtent extent, ColumnType... colsToFetch);
   151→
   152→  /**
   153→   * Entry point for reading multiple tablets' metadata. Generates a TabletsMetadata builder object
   154→   * and assigns the AmpleImpl client to that builder object. This allows readTablets() to be called
   155→   * from a ClientContext. Associated methods of the TabletsMetadata Builder class are used to
   156→   * generate the metadata.
   157→   */
   158→  TabletsMetadata.TableOptions readTablets();
   159→
   160→  /**
   161→   * Initiates mutating a single tablets persistent metadata. No data is persisted until the
   162→   * {@code mutate()} method is called on the returned object. If updating multiple tablets,
   163→   * consider using {@link #mutateTablets()}
   164→   *
   165→   * @param extent Mutates a tablet that has this table id and end row. The prev end row is not
   166→   *        considered or checked.
   167→   */
   168→  default TabletMutator mutateTablet(KeyExtent extent) {
   169→    throw new UnsupportedOperationException();
   170→  }
   171→
   172→  /**
   173→   * Use this when updating multiple tablets. Ensure the returns TabletsMutator is closed, or data
   174→   * may not be persisted.
   175→   */
   176→  default TabletsMutator mutateTablets() {
   177→    throw new UnsupportedOperationException();
   178→  }
   179→
   180→  /**
   181→   * An entry point for updating tablets metadata using a conditional writer. The returned mutator
   182→   * will buffer everything in memory until {@link ConditionalTabletsMutator#process()} is called.
   183→   * If buffering everything in memory is undesirable, then consider using
   184→   * {@link #conditionallyMutateTablets(Consumer)}
   185→   *
   186→   * @see ConditionalTabletMutator#submit(RejectionHandler)
   187→   */
   188→  default ConditionalTabletsMutator conditionallyMutateTablets() {
   189→    throw new UnsupportedOperationException();
   190→  }
   191→
   192→  /**
   193→   * An entry point for updating tablets metadata using a conditional writer asynchronously. This
   194→   * will process conditional mutations in the background as they are added. The benefit of this
   195→   * method over {@link #conditionallyMutateTablets()} is that it can avoid buffering everything in
   196→   * memory. Using this method may also be faster as it allows tablet metadata scans and conditional
   197→   * updates of tablets to run concurrently.
   198→   *
   199→   * @param resultsConsumer as conditional mutations are processed in the background their result is
   200→   *        passed to this consumer. This consumer should be thread safe as it may be called from a
   201→   *        different thread.
   202→   * @return A conditional tablet mutator that will asynchronously report results. Closing this
   203→   *         object will force everything to be processed and reported. The returned object is not
   204→   *         thread safe and is only intended to be used by a single thread.
   205→   * @see ConditionalTabletMutator#submit(RejectionHandler)
   206→   */
   207→  default AsyncConditionalTabletsMutator
   208→      conditionallyMutateTablets(Consumer<ConditionalResult> resultsConsumer) {
   209→    throw new UnsupportedOperationException();
   210→  }
   211→
   212→  default void putGcCandidates(TableId tableId, Collection<StoredTabletFile> candidates) {
   213→    throw new UnsupportedOperationException();
   214→  }
   215→
   216→  /**
   217→   * Unlike {@link #putGcCandidates(TableId, Collection)} this takes file and dir GC candidates.
   218→   */
   219→  default void putGcFileAndDirCandidates(TableId tableId, Collection<ReferenceFile> candidates) {
   220→    throw new UnsupportedOperationException();
   221→  }
   222→
   223→  /**
   224→   * Enum added to support unique candidate deletions in 2.1
   225→   */
   226→  default void deleteGcCandidates(DataLevel level, Collection<GcCandidate> candidates,
   227→      GcCandidateType type) {
   228→    throw new UnsupportedOperationException();
   229→  }
   230→
   231→  default Iterator<GcCandidate> getGcCandidates(DataLevel level) {
   232→    throw new UnsupportedOperationException();
   233→  }
   234→
   235→  /**
   236→   * Return an encoded delete marker Mutation to delete the specified TabletFile path. A
   237→   * ReferenceFile is used for the parameter because the Garbage Collector is optimized to store a
   238→   * directory for Tablet File. Otherwise, a {@link ReferencedTabletFile} object could be used. The
   239→   * tabletFilePathToRemove is validated and normalized before creating the mutation.
   240→   *
   241→   * @param tabletFilePathToRemove String full path of the TabletFile
   242→   * @return Mutation with encoded delete marker
   243→   */
   244→  default Mutation createDeleteMutation(ReferenceFile tabletFilePathToRemove) {
   245→    throw new UnsupportedOperationException();
   246→  }
   247→
   248→  /**
   249→   * This interface allows efficiently updating multiple tablets. Unless close is called, changes
   250→   * may not be persisted.
   251→   */
   252→  public interface TabletsMutator extends AutoCloseable {
   253→    TabletMutator mutateTablet(KeyExtent extent);
   254→
   255→    @Override
   256→    void close();
   257→  }
   258→
   259→  interface ConditionalResult {
   260→
   261→    /**
   262→     * This enum was created instead of using
   263→     * {@link org.apache.accumulo.core.client.ConditionalWriter.Status} because Ample has automated
   264→     * handling for most of the statuses of the conditional writer and therefore only a subset are
   265→     * expected to be passed out of Ample. This enum represents the subset that Ample will actually
   266→     * return.
   267→     */
   268→    enum Status {
   269→      ACCEPTED, REJECTED
   270→    }
   271→
   272→    /**
   273→     * Returns the status of the conditional mutation or may return a computed status of ACCEPTED in
   274→     * some cases, see {@link ConditionalTabletMutator#submit(RejectionHandler)} for details.
   275→     */
   276→    Status getStatus();
   277→
   278→    KeyExtent getExtent();
   279→
   280→    /**
   281→     * This can only be called when {@link #getStatus()} returns something other than
   282→     * {@link Status#ACCEPTED}. It reads that tablets metadata for a failed conditional mutation.
   283→     * This can be used to see why it was not accepted.
   284→     */
   285→    TabletMetadata readMetadata();
   286→  }
   287→
   288→  interface AsyncConditionalTabletsMutator extends AutoCloseable {
   289→    /**
   290→     * @return A fluent interface to conditional mutating a tablet. Ensure you call
   291→     *         {@link ConditionalTabletMutator#submit(RejectionHandler)} when finished.
   292→     */
   293→    OperationRequirements mutateTablet(KeyExtent extent);
   294→
   295→    /**
   296→     * Closing ensures that all mutations are processed and their results are reported.
   297→     */
   298→    @Override
   299→    void close();
   300→  }
   301→
   302→  interface ConditionalTabletsMutator extends AsyncConditionalTabletsMutator {
   303→
   304→    /**
   305→     * After creating one or more conditional mutations using {@link #mutateTablet(KeyExtent)}, call
   306→     * this method to process them using a {@link ConditionalWriter}
   307→     *
   308→     * @return The result from the {@link ConditionalWriter} of processing each tablet.
   309→     */
   310→    Map<KeyExtent,ConditionalResult> process();
   311→  }
   312→
   313→  /**
   314→   * Interface for changing a tablets persistent data.
   315→   */
   316→  interface TabletUpdates<T> {
   317→    T putPrevEndRow(Text per);
   318→
   319→    T putFile(ReferencedTabletFile path, DataFileValue dfv);
   320→
   321→    T putFile(StoredTabletFile path, DataFileValue dfv);
   322→
   323→    T deleteFile(StoredTabletFile path);
   324→
   325→    T putScan(StoredTabletFile path);
   326→
   327→    T deleteScan(StoredTabletFile path);
   328→
   329→    T putFlushId(long flushId);
   330→
   331→    T putFlushNonce(long flushNonce);
   332→
   333→    T putLocation(Location location);
   334→
   335→    T deleteLocation(Location location);
   336→
   337→    T putDirName(String dirName);
   338→
   339→    T putWal(LogEntry logEntry);
   340→
   341→    T deleteWal(LogEntry logEntry);
   342→
   343→    T putTime(MetadataTime time);
   344→
   345→    T putBulkFile(ReferencedTabletFile bulkref, FateId fateId);
   346→
   347→    T deleteBulkFile(StoredTabletFile bulkref);
   348→
   349→    T putSuspension(TServerInstance tserver, SteadyTime suspensionTime);
   350→
   351→    T deleteSuspension();
   352→
   353→    T putExternalCompaction(ExternalCompactionId ecid, CompactionMetadata ecMeta);
   354→
   355→    T deleteExternalCompaction(ExternalCompactionId ecid);
   356→
   357→    T putCompacted(FateId fateId);
   358→
   359→    T deleteCompacted(FateId fateId);
   360→
   361→    T putTabletAvailability(TabletAvailability tabletAvailability);
   362→
   363→    T setHostingRequested();
   364→
   365→    T deleteHostingRequested();
   366→
   367→    T putOperation(TabletOperationId opId);
   368→
   369→    T deleteOperation();
   370→
   371→    T putSelectedFiles(SelectedFiles selectedFiles);
   372→
   373→    T deleteSelectedFiles();
   374→
   375→    /**
   376→     * Deletes all the columns in the keys.
   377→     *
   378→     * @throws IllegalArgumentException if rows in keys do not match tablet row or column visibility
   379→     *         is not empty
   380→     */
   381→    T deleteAll(Collection<Map.Entry<Key,Value>> entries);
   382→
   383→    T setMerged();
   384→
   385→    T deleteMerged();
   386→
   387→    T putUserCompactionRequested(FateId fateId);
   388→
