   390→
   391→    T setUnSplittable(UnSplittableMetadata unSplittableMeta);
   392→
   393→    T deleteUnSplittable();
   394→
   395→    T putCloned();
   396→
   397→    T putTabletMergeability(TabletMergeabilityMetadata tabletMergeability);
   398→
   399→    /**
   400→     * By default the server lock is automatically added to mutations unless this method is set to
   401→     * false.
   402→     */
   403→    T automaticallyPutServerLock(boolean b);
   404→
   405→    T putMigration(TServerInstance tserver);
   406→
   407→    T deleteMigration();
   408→  }
   409→
   410→  interface TabletMutator extends TabletUpdates<TabletMutator> {
   411→    /**
   412→     * This method persist (or queues for persisting) previous put and deletes against this object.
   413→     * Unless this method is called, previous calls will never be persisted. The purpose of this
   414→     * method is to prevent partial changes in the case of an exception.
   415→     *
   416→     * <p>
   417→     * Implementors of this interface should ensure either all requested changes are persisted or
   418→     * none.
   419→     *
   420→     * <p>
   421→     * After this method is called, calling any method on this object will result in an exception.
   422→     */
   423→    void mutate();
   424→  }
   425→
   426→  /**
   427→   * A tablet operation is a mutually exclusive action that is running against a tablet. Its very
   428→   * important that every conditional mutation specifies requirements about operations in order to
   429→   * satisfy the mutual exclusion goal. This interface forces those requirements to specified by
   430→   * making it the only choice available before specifying other tablet requirements or mutations.
   431→   *
   432→   * @see MetadataSchema.TabletsSection.ServerColumnFamily#OPID_COLUMN
   433→   */
   434→  interface OperationRequirements {
   435→
   436→    /**
   437→     * This should be used to make changes to a hosted tablet and ensure the location is as
   438→     * expected. Hosted tablets should unload when an operation id set, but can update their
   439→     * metadata prior to unloading.
   440→     *
   441→     * @see MetadataSchema.TabletsSection.ServerColumnFamily#OPID_COLUMN
   442→     */
   443→    ConditionalTabletMutator requireLocation(Location location);
   444→
   445→    /**
   446→     * Require a specific operation with a unique id is present. This would be normally be called by
   447→     * the code executing that operation.
   448→     */
   449→    ConditionalTabletMutator requireOperation(TabletOperationId operationId);
   450→
   451→    /**
   452→     * Require that no mutually exclusive operations are running against this tablet.
   453→     */
   454→    ConditionalTabletMutator requireAbsentOperation();
   455→
   456→    /**
   457→     * Require an entire tablet is absent, so the tablet row has no columns. If the entire tablet is
   458→     * absent, then this implies the tablet operation is also absent so there is no need to specify
   459→     * that.
   460→     */
   461→    ConditionalTabletMutator requireAbsentTablet();
   462→  }
   463→
   464→  /**
   465→   * Convenience interface for handling conditional mutations with a status of REJECTED.
   466→   */
   467→  interface RejectionHandler extends Predicate<TabletMetadata> {
   468→
   469→    /**
   470→     * @return true if the handler should be called when a tablet no longer exists
   471→     */
   472→    default boolean callWhenTabletDoesNotExists() {
   473→      return false;
   474→    }
   475→
   476→    /**
   477→     * @return a RejectionHandler that considers that case where the tablet no longer exists as
   478→     *         accepted.
   479→     */
   480→    static RejectionHandler acceptAbsentTablet() {
   481→      return new Ample.RejectionHandler() {
   482→        @Override
   483→        public boolean callWhenTabletDoesNotExists() {
   484→          return true;
   485→        }
   486→
   487→        @Override
   488→        public boolean test(TabletMetadata tabletMetadata) {
   489→          return tabletMetadata == null;
   490→        }
   491→      };
   492→    }
   493→  }
   494→
   495→  interface ConditionalTabletMutator extends TabletUpdates<ConditionalTabletMutator> {
   496→
   497→    /**
   498→     * Require that a tablet has no future or current location set.
   499→     */
   500→    ConditionalTabletMutator requireAbsentLocation();
   501→
   502→    /**
   503→     * Require that a tablet currently has the specified future or current location.
   504→     */
   505→    ConditionalTabletMutator requireLocation(Location location);
   506→
   507→    ConditionalTabletMutator requireCurrentLocationNotEqualTo(TServerInstance tsi);
   508→
   509→    /**
   510→     * Requires the tablet to have the specified tablet availability before any changes are made.
   511→     */
   512→    ConditionalTabletMutator requireTabletAvailability(TabletAvailability tabletAvailability);
   513→
   514→    /**
   515→     * Requires the specified external compaction to exists
   516→     */
   517→    ConditionalTabletMutator requireCompaction(ExternalCompactionId ecid);
   518→
   519→    /**
   520→     * For the specified columns, requires the tablets metadata to be the same at the time of update
   521→     * as what is in the passed in tabletMetadata object.
   522→     */
   523→    ConditionalTabletMutator requireSame(TabletMetadata tabletMetadata, ColumnType type,
   524→        ColumnType... otherTypes);
   525→
   526→    ConditionalTabletMutator requireAbsentLogs();
   527→
   528→    /**
   529→     * Require that a tablet contain all the files in the set
   530→     */
   531→    ConditionalTabletMutator requireFiles(Set<StoredTabletFile> files);
   532→
   533→    /**
   534→     * Require that a tablet have less than or equals the specified number of files.
   535→     */
   536→    ConditionalTabletMutator requireLessOrEqualsFiles(long limit);
   537→
   538→    /**
   539→     * Requires that a tablet not have these loaded flags set.
   540→     */
   541→    ConditionalTabletMutator requireAbsentLoaded(Set<ReferencedTabletFile> files);
   542→
   543→    /**
   544→     * This check will run atomically on the server side and must pass in order for the tablet to be
   545→     * updated.
   546→     */
   547→    ConditionalTabletMutator requireCheckSuccess(TabletMetadataCheck check);
   548→
   549→    /**
   550→     * Requires that a tablet be migrating to the given tserver
   551→     */
   552→    ConditionalTabletMutator requireMigration(TServerInstance tserver);
   553→
   554→    /**
   555→     * <p>
   556→     * Ample provides the following features on top of the conditional writer to help automate
   557→     * handling of edges cases that arise when using the conditional writer.
   558→     * <ul>
   559→     * <li>Automatically resubmit conditional mutations with a status of
   560→     * {@link org.apache.accumulo.core.client.ConditionalWriter.Status#UNKNOWN}.</li>
   561→     * <li>When a mutation is rejected (status of
   562→     * {@link org.apache.accumulo.core.client.ConditionalWriter.Status#REJECTED}) it will read the
   563→     * tablets metadata and call the passed rejectionHandler to determine if the mutation should be
   564→     * considered as accepted.</li>
   565→     * <li>For status of
   566→     * {@link org.apache.accumulo.core.client.ConditionalWriter.Status#INVISIBLE_VISIBILITY} and
   567→     * {@link org.apache.accumulo.core.client.ConditionalWriter.Status#VIOLATED} ample will throw an
   568→     * exception. This is done so that all code does not have to deal with these unexpected
   569→     * statuses.</li>
   570→     * </ul>
   571→     *
   572→     * <p>
   573→     * The motivation behind the rejectionHandler is to help sort things out when conditional
   574→     * mutations are submitted twice and the subsequent submission is rejected even though the first
   575→     * submission was accepted. There are two causes for this. First when a threads is running in
   576→     * something like FATE it may submit a mutation and the thread dies before it sees the response.
   577→     * Later FATE will run the code again for a second time, submitting a second mutation. The
   578→     * second cause is ample resubmitting on unknown as mentioned above. Below are a few examples
   579→     * that go over how Ample will handle these different situations.
   580→     *
   581→     * <h4>Example 1</h4>
   582→     *
   583→     * <ul>
   584→     * <li>Conditional mutation CM1 with a condition requiring an absent location that sets a future
   585→     * location is submitted. When its submitted to ample a rejectionHandler is set that checks the
   586→     * future location.</li>
   587→     * <li>Inside Ample CM1 is submitted to a conditional writer and returns a status of UNKNOWN,
   588→     * but it actually succeeded. This could be caused by the mutation succeeding and the tablet
   589→     * server dying just before it reports back.</li>
   590→     * <li>Ample sees the UNKNOWN status and resubmits CM1 for a second time. Because the future
   591→     * location was set, the mutation is returned to ample with a status of rejected by the
   592→     * conditional writer.</li>
   593→     * <li>Because the mutation was rejected, ample reads the tablet metadata and calls the
   594→     * rejectionHandler. The rejectionHandler sees the future location was set and reports that
   595→     * everything is ok, therefore ample reports the status as ACCEPTED.</li>
   596→     * </ul>
   597→     *
   598→     * <h4>Example 2</h4>
   599→     *
   600→     * <ul>
   601→     * <li>Conditional mutation CM2 with a condition requiring an absent location that sets a future
   602→     * location is submitted. When its submitted to ample a rejectionHandler is set that checks the
   603→     * future location.</li>
   604→     * <li>Inside Ample CM2 is submitted to a conditional writer and returns a status of UNKNOWN,
   605→     * but it actually never made it to the tserver. This could be caused by the tablet server dying
   606→     * just after a network connection was established to send the mutation.</li>
   607→     * <li>Ample sees the UNKNOWN status and resubmits CM2 for a second time. There is no future
   608→     * location set so the mutation is returned to ample with a status of accepted by the
   609→     * conditional writer.</li>
   610→     * <li>Because the mutation was accepted, ample never calls the rejectionHandler and returns it
   611→     * as accepted.</li>
   612→     * </ul>
   613→     *
   614→     * <h4>Example 3</h4>
   615→     *
   616→     * <ul>
   617→     * <li>Conditional mutation CM3 with a condition requiring an absent operation that sets the
   618→     * operation id to a fate transaction id is submitted. When it's submitted to ample a
   619→     * rejectionHandler is set that checks if the operation id equals the fate transaction id.</li>
   620→     * <li>The thread running the fate operation dies after submitting the mutation but before
   621→     * seeing it was actually accepted.</li>
   622→     * <li>Later fate creates an identical mutation to CM3, lets call it CM3.2, and resubmits it
   623→     * with the same rejection handler.</li>
   624→     * <li>CM3.2 is rejected because the operation id is not absent.</li>
   625→     * <li>Because the mutation was rejected, ample calls the rejectionHandler. The rejectionHandler
   626→     * sees in the tablet metadata that the operation id is its fate transaction id and reports back
   627→     * true</li>
   628→     * <li>When rejectionHandler reports true, ample reports the mutation as accepted.</li>
   629→     * </ul>
   630→     *
   631→     * @param rejectionHandler if the conditional mutation comes back with a status of
   632→     *        {@link org.apache.accumulo.core.client.ConditionalWriter.Status#REJECTED} then read
   633→     *        the tablets metadata and apply this check to see if it should be considered as
   634→     *        {@link org.apache.accumulo.core.client.ConditionalWriter.Status#ACCEPTED} in the
   635→     *        return of {@link ConditionalTabletsMutator#process()}. The rejection handler is only
   636→     *        called when a tablets metadata exists. If ample reads a tablet's metadata and the
   637→     *        tablet no longer exists, then ample will not call the rejectionHandler with null
   638→     *        (unless {@link RejectionHandler#callWhenTabletDoesNotExists()} returns true). It will
   639→     *        let the rejected status carry forward in this case.
   640→     */
   641→    void submit(RejectionHandler rejectionHandler);
   642→
   643→    /**
   644→     * Overloaded version of {@link #submit(RejectionHandler)} that takes a short description of the
   645→     * operation to assist with debugging.
   646→     *
   647→     * @param rejectionHandler The rejection handler
   648→     * @param description A short description of the operation (e.g., "bulk import", "compaction")
   649→     */
   650→    void submit(RejectionHandler rejectionHandler, Supplier<String> description);
   651→
   652→  }
   653→
   654→  /**
   655→   * Create a Bulk Load In Progress flag in the metadata table
   656→   *
   657→   * @param path The bulk directory filepath
   658→   * @param fateId The FateId of the Bulk Import Fate operation.
   659→   */
   660→  default void addBulkLoadInProgressFlag(String path, FateId fateId) {
   661→    throw new UnsupportedOperationException();
   662→  }
   663→
   664→  /**
   665→   * Remove a Bulk Load In Progress flag from the metadata table.
   666→   *
   667→   * @param path The bulk directory filepath
   668→   */
   669→  default void removeBulkLoadInProgressFlag(String path) {
   670→    throw new UnsupportedOperationException();
   671→  }
   672→
   673→  default ScanServerRefStore scanServerRefs() {
   674→    throw new UnsupportedOperationException();
   675→  }
   676→}
