    36→/**
    37→ * Transaction Store: a place to save transactions
    38→ *
    39→ * A transaction consists of a number of operations. To use, first create a fate transaction id, and
    40→ * then seed the transaction with an initial operation. An executor service can then execute the
    41→ * transaction's operation, possibly pushing more operations onto the transaction as each step
    42→ * successfully completes. If a step fails, the stack can be unwound, undoing each operation.
    43→ */
    44→public interface FateStore<T> extends ReadOnlyFateStore<T>, AutoCloseable {
    45→
    46→  /**
    47→   * Create a new fate transaction id
    48→   *
    49→   * @return a new FateId
    50→   */
    51→  FateId create();
    52→
    53→  interface Seeder<T> extends AutoCloseable {
    54→
    55→    /**
    56→     * Attempts to seed a transaction with the given repo if it does not exist. A fateId will be
    57→     * derived from the fateKey. If seeded, sets the following data for the fateId in the store.
    58→     *
    59→     * <ul>
    60→     * <li>Set the fate op</li>
    61→     * <li>Set the status to SUBMITTED</li>
    62→     * <li>Set the fate key</li>
    63→     * <li>Sets autocleanup only if true</li>
    64→     * <li>Sets the creation time</li>
    65→     * </ul>
    66→     *
    67→     * @return The return type is only intended for testing it may not be correct in the face of
    68→     *         failures. When there are no failures returns optional w/ the fate id set if seeded
    69→     *         and empty optional otherwise. If there was a failure this could return an empty
    70→     *         optional when it actually succeeded.
    71→     */
    72→    CompletableFuture<Optional<FateId>> attemptToSeedTransaction(Fate.FateOperation fateOp,
    73→        FateKey fateKey, Repo<T> repo, boolean autoCleanUp);
    74→
    75→    @Override
    76→    void close();
