   111→      Predicate<ZooUtil.LockID> isLockHeld, int maxDeferred, FateIdGenerator fateIdGenerator) {
   112→    super(lockID, isLockHeld, maxDeferred, fateIdGenerator);
   113→    this.context = Objects.requireNonNull(context);
   114→    this.tableName = Objects.requireNonNull(tableName);
   115→    this.writer = Suppliers.memoize(() -> {
   116→      try {
