   178→  private FateMutator<T> buildMutator(Supplier<FateMutator<T>> mutatorFactory,
   179→      Fate.FateOperation fateOp, Repo<T> repo, boolean autoCleanUp) {
   180→    var mutator = mutatorFactory.get();
   181→    mutator =
   182→        mutator.putFateOp(serializeTxInfo(fateOp)).putRepo(1, repo).putStatus(TStatus.SUBMITTED);
   183→    if (autoCleanUp) {
   184→      mutator = mutator.putAutoClean(serializeTxInfo(autoCleanUp));
   185→    }
   186→    return mutator;
   187→  }
