   189→  private boolean seedTransaction(Supplier<FateMutator<T>> mutatorFactory, String logId,
   190→      Fate.FateOperation fateOp, Repo<T> repo, boolean autoCleanUp) {
   191→    var mutator = buildMutator(mutatorFactory, fateOp, repo, autoCleanUp);
   192→    int maxAttempts = 5;
   193→    for (int attempt = 0; attempt < maxAttempts; attempt++) {
   194→      var status = mutator.tryMutate();
   195→      if (status == FateMutator.Status.ACCEPTED) {
   196→        // signal to the super class that a new fate transaction was seeded and is ready to run
   197→        seededTx();
   198→        log.trace("Attempt to seed {} returned {}", logId, status);
   199→        return true;
   200→      } else if (status == FateMutator.Status.REJECTED) {
   201→        log.debug("Attempt to seed {} returned {}", logId, status);
   202→        return false;
   203→      } else if (status == FateMutator.Status.UNKNOWN) {
   204→        // At this point can not reliably determine if the conditional mutation was successful or
   205→        // not because no reservation was acquired. For example since no reservation was acquired it
   206→        // is possible that seeding was a success and something immediately picked it up and started
   207→        // operating on it and changing it. If scanning after that point can not conclude success or
   208→        // failure. Another situation is that maybe the fateId already existed in a seeded form
   209→        // prior to getting this unknown.
   210→        log.debug("Attempt to seed {} returned {} status, retrying", logId, status);
   211→        UtilWaitThread.sleep(250);
   212→      }
   213→    }
   214→
   215→    log.warn("Repeatedly received unknown status when attempting to seed {}", logId);
   216→    return false;
   217→  }
