   219→  @Override
   220→  public Optional<FateTxStore<T>> tryReserve(FateId fateId) {
   221→    verifyLock(lockID, fateId);
   222→    // Create a unique FateReservation for this reservation attempt
   223→    FateReservation reservation = FateReservation.from(lockID, UUID.randomUUID());
   224→
   225→    // requiring any status prevents creating an entry if the fate id doesn't exist
   226→    FateMutator.Status status =
   227→        newMutator(fateId).requireStatus(TStatus.values()).putReservedTx(reservation).tryMutate();
   228→    if (status.equals(FateMutator.Status.ACCEPTED)) {
   229→      return Optional.of(new FateTxStoreImpl(fateId, reservation));
   230→    } else if (status.equals(FateMutator.Status.UNKNOWN)) {
   231→      // If the status is UNKNOWN, this means an error occurred after the mutation was
   232→      // sent to the TabletServer, and it is unknown if the mutation was written. We
   233→      // need to check if the mutation was written and if it was written by this
   234→      // attempt at reservation. If it was written by this reservation attempt,
   235→      // we can return the FateTxStore since it was successfully reserved in this
   236→      // attempt, otherwise we return empty (was written by another reservation
   237→      // attempt or was not written at all).
   238→      try (Scanner scanner = context.createScanner(tableName, Authorizations.EMPTY)) {
   239→        scanner.setRange(getRow(fateId));
   240→        scanner.fetchColumn(TxAdminColumnFamily.RESERVATION_COLUMN.getColumnFamily(),
   241→            TxAdminColumnFamily.RESERVATION_COLUMN.getColumnQualifier());
   242→        FateReservation persistedRes =
   243→            scanner.stream().map(entry -> FateReservation.deserialize(entry.getValue().get()))
   244→                .findFirst().orElse(null);
   245→        if (persistedRes != null && persistedRes.equals(reservation)) {
   246→          return Optional.of(new FateTxStoreImpl(fateId, reservation));
   247→        }
   248→      } catch (TableNotFoundException e) {
   249→        throw new IllegalStateException(tableName + " not found!", e);
   250→      }
   251→    }
   252→    return Optional.empty();
   253→  }
   254→
   255→  @Override
   256→  public void deleteDeadReservations() {
   257→    for (Entry<FateId,FateReservation> activeRes : getActiveReservations().entrySet()) {
   258→      FateId fateId = activeRes.getKey();
   259→      FateReservation reservation = activeRes.getValue();
   260→      if (!isLockHeld.test(reservation.getLockID())) {
   261→        var status = newMutator(fateId).putUnreserveTx(reservation).tryMutate();
   262→        if (status == FateMutator.Status.ACCEPTED) {
   263→          // Technically, this should also be logged for the case where the mutation status
   264→          // is UNKNOWN, but the mutation was actually written (fate id was unreserved)
   265→          // but there is no way to tell if it was unreserved from this mutation or another
   266→          // thread simply unreserving the transaction
   267→          log.trace("Deleted the dead reservation {} for fate id {}", reservation, fateId);
   268→        }
   269→        // No need to verify the status... If it is ACCEPTED, we have successfully unreserved
   270→        // the dead transaction. If it is REJECTED, the reservation has changed (i.e.,
   271→        // has been unreserved so no need to do anything, or has been unreserved and reserved
   272→        // again in which case we don't want to change it). If it is UNKNOWN, the mutation
   273→        // may or may not have been written. If it was written, we have successfully unreserved
   274→        // the dead transaction. If it was not written, the next cycle/call to
   275→        // deleteDeadReservations() will try again.
   276→      }
   277→    }
   278→  }
