   280→  @Override
   281→  protected Stream<FateIdStatus> getTransactions(EnumSet<TStatus> statuses) {
   282→    try {
   283→      Scanner scanner = context.createScanner(tableName, Authorizations.EMPTY);
   284→      scanner.setRange(new Range());
   285→      RowFateStatusFilter.configureScanner(scanner, statuses);
   286→      // columns fetched here must be in/added to TxAdminColumnFamily for locality group benefits
   287→      TxAdminColumnFamily.STATUS_COLUMN.fetch(scanner);
   288→      TxAdminColumnFamily.RESERVATION_COLUMN.fetch(scanner);
   289→      TxAdminColumnFamily.FATE_OP_COLUMN.fetch(scanner);
   290→      return scanner.stream().onClose(scanner::close).map(e -> {
   291→        String txUUIDStr = e.getKey().getRow().toString();
   292→        FateId fateId = FateId.from(fateInstanceType, txUUIDStr);
   293→        SortedMap<Key,Value> rowMap;
   294→        TStatus status = TStatus.UNKNOWN;
   295→        FateReservation reservation = null;
   296→        Fate.FateOperation fateOp = null;
   297→        try {
   298→          rowMap = WholeRowIterator.decodeRow(e.getKey(), e.getValue());
   299→        } catch (IOException ex) {
   300→          throw new RuntimeException(ex);
   301→        }
   302→        // Always expect a status, optionally expect a fate operation (present if seeded)
   303→        // and optionally expect a fate reservation (present if currently reserved)
   304→        Preconditions.checkState(rowMap.size() >= 1 && rowMap.size() <= 3,
   305→            "Invalid row seen: %s. Expected to see tx status and optionally a fate op and "
   306→                + "optionally a fate reservation",
   307→            rowMap);
   308→        for (Entry<Key,Value> entry : rowMap.entrySet()) {
   309→          Text colf = entry.getKey().getColumnFamily();
   310→          Text colq = entry.getKey().getColumnQualifier();
   311→          Value val = entry.getValue();
   312→          switch (colq.toString()) {
   313→            case TxAdminColumnFamily.STATUS:
   314→              status = TStatus.valueOf(val.toString());
   315→              break;
   316→            case TxAdminColumnFamily.RESERVATION:
   317→              reservation = FateReservation.deserialize(val.get());
   318→              break;
   319→            case TxAdminColumnFamily.FATE_OP:
   320→              fateOp = (Fate.FateOperation) deserializeTxInfo(TxInfo.FATE_OP, val.get());
   321→              break;
   322→            default:
   323→              throw new IllegalStateException("Unexpected column seen: " + colf + ":" + colq);
   324→          }
   325→        }
   326→        final TStatus finalStatus = status;
   327→        final Optional<FateReservation> finalReservation = Optional.ofNullable(reservation);
   328→        final Optional<Fate.FateOperation> finalFateOp = Optional.ofNullable(fateOp);
   329→        return new FateIdStatusBase(fateId) {
   330→          @Override
   331→          public TStatus getStatus() {
   332→            return finalStatus;
   333→          }
   334→
   335→          @Override
   336→          public Optional<FateReservation> getFateReservation() {
   337→            return finalReservation;
   338→          }
   339→
   340→          @Override
   341→          public Optional<Fate.FateOperation> getFateOperation() {
   342→            return finalFateOp;
   343→          }
   344→        };
   345→      });
   346→    } catch (TableNotFoundException e) {
   347→      throw new IllegalStateException(tableName + " not found!", e);
   348→    }
   349→  }
