   414→  private class BatchSeeder implements Seeder<T> {
   415→    private final AtomicBoolean closed = new AtomicBoolean(false);
   416→
   417→    private final Map<FateId,Pair<FateMutator<T>,CompletableFuture<Optional<FateId>>>> pending =
   418→        new HashMap<>();
   419→
   420→    @Override
   421→    public CompletableFuture<Optional<FateId>> attemptToSeedTransaction(FateOperation fateOp,
   422→        FateKey fateKey, Repo<T> repo, boolean autoCleanUp) {
   423→      Preconditions.checkState(!closed.get(), "Can't attempt to seed with a closed seeder.");
   424→
   425→      final var fateId = fateIdGenerator.fromTypeAndKey(type(), fateKey);
   426→      // If not already submitted, add to the pending list and return the future
   427→      // or the existing future if duplicate. The pending map will store the mutator
   428→      // to be processed on close in a one batch.
   429→      return pending.computeIfAbsent(fateId, id -> {
   430→        FateMutator<T> mutator = seedTransaction(fateOp, fateKey, fateId, repo, autoCleanUp);
   431→        CompletableFuture<Optional<FateId>> future = new CompletableFuture<>();
   432→        return new Pair<>(mutator, future);
   433→      }).getSecond();
   434→    }
   435→
   436→    @Override
   437→    public void close() {
   438→      closed.set(true);
   439→
   440→      int maxAttempts = 5;
   441→
   442→      // This loop will submit all the pending mutations as one batch
   443→      // to a conditional writer and any known results will be removed
   444→      // from the pending map. Unknown results will be re-attempted up
   445→      // to the maxAttempts count
   446→      for (int attempt = 0; attempt < maxAttempts && !pending.isEmpty(); attempt++) {
   447→        var currentResults = tryMutateBatch();
   448→        for (Entry<FateId,ConditionalWriter.Status> result : currentResults.entrySet()) {
   449→          var fateId = result.getKey();
   450→          var status = result.getValue();
   451→          var future = pending.get(fateId).getSecond();
   452→          switch (result.getValue()) {
   453→            case ACCEPTED:
   454→              seededTx();
   455→              log.trace("Attempt to seed {} returned {}", fateId.canonical(), status);
   456→              // Complete the future with the fatId and remove from pending
   457→              future.complete(Optional.of(fateId));
   458→              pending.remove(fateId);
   459→              break;
   460→            case REJECTED:
   461→              log.debug("Attempt to seed {} returned {}", fateId.canonical(), status);
   462→              // Rejected so complete with an empty optional and remove from pending
   463→              future.complete(Optional.empty());
   464→              pending.remove(fateId);
   465→              break;
   466→            case UNKNOWN:
   467→              log.debug("Attempt to seed {} returned {} status, retrying", fateId.canonical(),
   468→                  status);
   469→              // unknown, so don't remove from map so that we try again if still under
   470→              // max attempts
   471→              break;
   472→            default:
   473→              // do not expect other statuses
   474→              throw new IllegalStateException("Unhandled status for mutation " + status);
   475→          }
   476→        }
   477→
   478→        if (!pending.isEmpty()) {
   479→          // At this point can not reliably determine if the unknown pending mutations were
   480→          // successful or not because no reservation was acquired. For example since no
   481→          // reservation was acquired it is possible that seeding was a success and something
   482→          // immediately picked it up and started operating on it and changing it.
   483→          // If scanning after that point can not conclude success or failure. Another situation
   484→          // is that maybe the fateId already existed in a seeded form prior to getting this
   485→          // unknown.
   486→          UtilWaitThread.sleep(250);
   487→        }
   488→      }
   489→
   490→      // Any remaining will be UNKNOWN status, so complete the futures with an optional empty
   491→      pending.forEach((fateId, pair) -> {
   492→        pair.getSecond().complete(Optional.empty());
   493→        log.warn("Repeatedly received unknown status when attempting to seed {}",
   494→            fateId.canonical());
   495→      });
   496→    }
   497→
   498→    // Submit all the pending mutations to a single conditional writer
   499→    // as one batch and return the results for each mutation
   500→    private Map<FateId,ConditionalWriter.Status> tryMutateBatch() {
   501→      if (pending.isEmpty()) {
   502→        return Map.of();
   503→      }
   504→
   505→      final Map<FateId,ConditionalWriter.Status> resultsMap = new HashMap<>();
   506→      try {
   507→        Iterator<ConditionalWriter.Result> results = writer.get()
   508→            .write(pending.values().stream().map(pair -> pair.getFirst().getMutation()).iterator());
   509→        while (results.hasNext()) {
   510→          var result = results.next();
   511→          var row = new Text(result.getMutation().getRow());
   512→          resultsMap.put(FateId.from(FateInstanceType.USER, row.toString()), result.getStatus());
   513→        }
   514→      } catch (AccumuloException | AccumuloSecurityException e) {
   515→        throw new IllegalStateException(e);
   516→      }
   517→      return resultsMap;
   518→    }
   519→  }
