   692→  static Text invertRepo(int position) {
   693→    Preconditions.checkArgument(REPO_RANGE.contains(position),
   694→        "Position %s is not in the valid range of [0,%s]", position, MAX_REPOS);
   695→    return new Text(String.format("%02d", MAX_REPOS - position));
   696→  }
   697→
   698→  static Integer restoreRepo(Text invertedPosition) {
   699→    int position = MAX_REPOS - Integer.parseInt(invertedPosition.toString());
   700→    Preconditions.checkArgument(REPO_RANGE.contains(position),
   701→        "Position %s is not in the valid range of [0,%s]", position, MAX_REPOS);
   702→    return position;
   703→  }
   704→
   705→  private ConditionalWriter createConditionalWriterForFateTable(String tableName)
   706→      throws TableNotFoundException {
   707→    int maxThreads =
   708→        context.getConfiguration().getCount(Property.MANAGER_FATE_CONDITIONAL_WRITER_THREADS_MAX);
   709→    ConditionalWriterConfig cwConfig = new ConditionalWriterConfig().setMaxWriteThreads(maxThreads);
   710→    return context.createConditionalWriter(tableName, cwConfig);
   711→  }
   712→
   713→  @Override
   714→  public void close() {
   715→    writer.get().close();
   716→  }
   717→}
