protected ConditionalWriter createConditionalWriter(Ample.DataLevel dataLevel) {
  // Use the shared conditional writer supplier if available
  if (writerSupplierFunction != null) {
    return writerSupplierFunction.apply(dataLevel).get();
  }

  // Fallback to creating a new conditional writer (for backwards compatibility with tests)
  if (dataLevel == Ample.DataLevel.ROOT) {
    return new RootConditionalWriter(context);
  } else {
    try {
      return context.createConditionalWriter(getTableMapper().apply(dataLevel));
    } catch (Exception e) {
      throw new RuntimeException("Failed to create conditional writer for " + dataLevel, e);
    }
  }
}

