/*
 * Test to verify that Ample creates a single conditional writer per data level
 * and reuses it across multiple conditional mutation operations.
 */
package org.apache.accumulo.test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.HashSet;
import java.util.Set;
import java.util.concurrent.atomic.AtomicInteger;

import org.apache.accumulo.core.client.Accumulo;
import org.apache.accumulo.core.client.AccumuloClient;
import org.apache.accumulo.core.client.ConditionalWriter;
import org.apache.accumulo.core.client.admin.NewTableConfiguration;
import org.apache.accumulo.core.data.TableId;
import org.apache.accumulo.core.dataImpl.KeyExtent;
import org.apache.accumulo.core.metadata.schema.Ample;
import org.apache.accumulo.core.metadata.schema.TabletOperationId;
import org.apache.accumulo.core.metadata.schema.TabletOperationType;
import org.apache.accumulo.harness.SharedMiniClusterBase;
import org.apache.accumulo.server.ServerContext;
import org.apache.accumulo.server.metadata.ServerAmpleImpl;
import org.apache.hadoop.io.Text;
import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

public class SingleConditionalWriterTest extends SharedMiniClusterBase {

  @BeforeAll
  public static void setup() throws Exception {
    SharedMiniClusterBase.startMiniCluster();
  }

  @AfterAll
  public static void teardown() {
    SharedMiniClusterBase.stopMiniCluster();
  }

  @Test
  public void testSingleConditionalWriterReuse() throws Exception {
    try (AccumuloClient client = Accumulo.newClient().from(getClientProps()).build()) {
      String tableName = getUniqueNames(1)[0];
      client.tableOperations().create(tableName, new NewTableConfiguration());

      TableId tableId = TableId.of(client.tableOperations().tableIdMap().get(tableName));
      ServerContext serverContext = getCluster().getServerContext();

      // Create ServerAmpleImpl instance
      ServerAmpleImpl ample = new ServerAmpleImpl(serverContext);

      // Verify that we can get conditional writer suppliers for different data levels
      var metadataSupplier = ample.getConditionalWriterSupplier(Ample.DataLevel.METADATA);
      var userSupplier = ample.getConditionalWriterSupplier(Ample.DataLevel.USER);

      assertNotNull(metadataSupplier, "Metadata conditional writer supplier should not be null");
      assertNotNull(userSupplier, "User conditional writer supplier should not be null");

      // Get the same supplier multiple times and verify it's the same writer
      ConditionalWriter writer1 = metadataSupplier.get();
      ConditionalWriter writer2 = metadataSupplier.get();

      assertTrue(writer1 == writer2, "Multiple calls to get() should return the same writer instance");

      // Test that different data levels have different writers
      ConditionalWriter userWriter = userSupplier.get();
      assertTrue(writer1 != userWriter, "Different data levels should have different writers");

      // Create multiple conditional mutators and verify they use the same writer
      Set<ConditionalWriter> writers = new HashSet<>();
      int numMutators = 5;

      for (int i = 0; i < numMutators; i++) {
        KeyExtent extent = new KeyExtent(tableId, new Text(String.format("row%02d", i + 1)),
            new Text(String.format("row%02d", i)));

        try (var mutator = ample.conditionallyMutateTablets()) {
          // Create a conditional mutation - we don't actually need to submit it
          // Just creating the mutator tests that it can get the writer
          var tabletMutator = mutator.mutateTablet(extent);

          // The writer is obtained when process() is called, but we can verify
          // the structure is correct by checking the mutator was created successfully
          assertNotNull(tabletMutator, "Tablet mutator should be created successfully");
        }
      }

      System.out.println("Test passed: Single conditional writer is reused across multiple operations");
    }
  }

  @Test
  public void testConditionalWriterConfiguration() throws Exception {
    try (AccumuloClient client = Accumulo.newClient().from(getClientProps()).build()) {
      ServerContext serverContext = getCluster().getServerContext();

      // Create ServerAmpleImpl instance
      ServerAmpleImpl ample = new ServerAmpleImpl(serverContext);

      // Verify configuration property exists and can be read
      int maxThreads = serverContext.getConfiguration()
          .getCount(org.apache.accumulo.core.conf.Property.MANAGER_AMPLE_CONDITIONAL_WRITER_THREADS_MAX);

      assertTrue(maxThreads > 0, "Configuration property should have a positive value");
      System.out.println("Configured max threads for Ample conditional writer: " + maxThreads);
    }
  }
}

