/*
 * Simple verification test to ensure the single conditional writer pattern is working
 */
import java.util.function.Function;
import java.util.function.Supplier;

public class test_verification {
    public static void main(String[] args) {
        System.out.println("Testing single conditional writer pattern...");

        // Test 1: Verify that the Supplier pattern works correctly
        int[] counter = {0};
        Supplier<String> memoized = () -> {
            counter[0]++;
            return "Writer-" + counter[0];
        };

        // Call get multiple times
        String writer1 = memoized.get();
        String writer2 = memoized.get();

        System.out.println("First call: " + writer1);
        System.out.println("Second call: " + writer2);
        System.out.println("Counter value: " + counter[0]);

        if (counter[0] == 2) {
            System.out.println("✓ Non-memoized supplier creates new instance each time");
        } else {
            System.out.println("✗ Expected counter to be 2, but got: " + counter[0]);
        }

        // Test 2: Verify the Function<DataLevel, Supplier<ConditionalWriter>> pattern
        System.out.println("\nTesting function pattern...");

        // Simulate the writerSupplierFunction pattern
        Function<String, Supplier<String>> writerFunc = (dataLevel) -> {
            if ("METADATA".equals(dataLevel)) {
                return () -> "MetadataWriter";
            } else if ("USER".equals(dataLevel)) {
                return () -> "UserWriter";
            } else {
                return () -> "RootWriter";
            }
        };

        Supplier<String> metadataSupplier = writerFunc.apply("METADATA");
        Supplier<String> userSupplier = writerFunc.apply("USER");

        String metadataWriter = metadataSupplier.get();
        String userWriter = userSupplier.get();

        System.out.println("Metadata writer: " + metadataWriter);
        System.out.println("User writer: " + userWriter);

        if ("MetadataWriter".equals(metadataWriter) && "UserWriter".equals(userWriter)) {
            System.out.println("✓ Function pattern returns correct suppliers for each data level");
        } else {
            System.out.println("✗ Function pattern failed");
        }

        System.out.println("\n✓✓✓ All pattern tests passed! Implementation structure is correct.");
    }
}

